const data = $input.first().json;
const workflowConfig = $('Workflow Configuration').first().json;
const correctDriverId = workflowConfig.driver_id;
const optimizedOrder = data.optimized_order;
const legs = data.legs;
const routeDate = data.route_date || workflowConfig.route_date;
const departureTime = data.departure_time || workflowConfig.departure_time;
const customers = workflowConfig.customers_list;

// ⏱️ Her durakta geçirilen süre (saniye cinsinden)
const SERVICE_TIME_SECONDS = 7 * 60; // 7 dakika

const timeParts = departureTime.split(':').map(Number);
const departureMinutes = timeParts[0] * 60 + timeParts[1];

const stops = [];
let cumulativeSeconds = 0;

for (let i = 0; i < legs.length; i++) {
  const leg = legs[i];
  const durationSeconds = parseInt(leg.duration.replace('s', ''), 10);
  const distanceMeters = leg.distanceMeters || 0;
  cumulativeSeconds += durationSeconds;

  // Son leg (depoya dönüş) atla
  if (i < legs.length - 1) {
    const customerIndex = (optimizedOrder && optimizedOrder.length > 0) ? optimizedOrder[i] : i;
    const customer = customers[customerIndex] || customers[i];
    if (!customer) continue;

    // ETA hesapla (bu durağa varış saati)
    const etaTotalMinutes = departureMinutes + Math.round(cumulativeSeconds / 60);
    const etaH = Math.floor(etaTotalMinutes / 60) % 24;
    const etaM = etaTotalMinutes % 60;
    const etaStr = routeDate + 'T' + String(etaH).padStart(2,'0') + ':' + String(etaM).padStart(2,'0') + ':00';

    stops.push({
      order_id: customer.order_id || null,
      customer_name: customer.customer_name || null,
      customer_phone: customer.customer_phone || null,
      address: customer.address,
      route_order: i + 1,
      eta: etaStr,
      estimated_duration: durationSeconds,
      distance: distanceMeters,
      driver_id: correctDriverId,
      route_type: data.route_type || workflowConfig.route_type,
      route_date: routeDate
    });

    // ✅ Bir sonraki durağın ETA'sı için servis süresini ekle
    cumulativeSeconds += SERVICE_TIME_SECONDS;
  }
}

return [{ json: {
  stops,
  total_distance: data.total_distance,
  total_duration: data.total_duration,
  driver_id: correctDriverId,
  route_type: data.route_type || workflowConfig.route_type,
  route_date: routeDate,
  departure_time: departureTime
} }];

const data = $input.first().json;
const stops = data.stops || [];
const routeType = data.route_type || 'pickup';
const actionNL = routeType === 'pickup' ? 'ophalen' : 'leveren';
const routeDate = data.route_date || '';

const dateObj = new Date(routeDate + 'T12:00:00');
const dayName = dateObj.toLocaleDateString('nl-BE', { weekday: 'long' });
const dayNum = dateObj.getDate();
const monthName = dateObj.toLocaleDateString('nl-BE', { month: 'long' });
const dateStr = `${dayName} ${dayNum} ${monthName}`;

return stops
  .filter(s => s.customer_phone)
  .map(s => ({
    json: {
      phone: s.customer_phone.replace(/^0/, '32').replace(/\D/g, ''),
      message: `Beste ${s.customer_name},\n\n🕐 Ons team zal op *${dateStr}* rond *${s.estimatedArrival}* bij u zijn.\n\nGelieve aanwezig te zijn voor het *${actionNL}* van uw tapijt(en).\n\nBedankt voor uw vertrouwen! 🙏\n— *Team AYKA Tapis*`
    }
  }));

